    (101, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "expl_id", "widgettype": "combo", "dvquerytext": "Select expl_id as id, name as idval FROM exploitation WHERE expl_id IS NOT NULL", "isNullValue": "true", "layoutorder": 1}]'),
    (105, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "Exploitation", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER BY name", "isNullValue": "true", "layoutorder": 1}, {"label": "Тип вузла:", "datatype": "text", "columnname": "Node type", "widgettype": "combo", "dvquerytext": "Select id as id, id as idval FROM cat_feature_node join cat_feature USING (id) WHERE id IS NOT NULL AND active ORDER BY id", "isNullValue": "true", "layoutorder": 2}]'),
    (102, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "Exploitation", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER by name", "isNullValue": "true", "layoutorder": 1}, {"label": "Dma:", "datatype": "text", "columnname": "Dma", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM dma WHERE dma_id != -1 and dma_id!=0 ORDER BY name", "isNullValue": "true", "layoutorder": 2}, {"label": "Період:", "datatype": "text", "columnname": "Period", "widgettype": "combo", "dvquerytext": "Select code as id, code as idval FROM ext_cat_period WHERE id IS NOT NULL ORDER BY end_date DESC", "isNullValue": "true", "layoutorder": 1}]'),
    (103, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "exploitation", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER by name", "isNullValue": "true", "layoutorder": 1}, {"label": "З Дати", "datatype": "text", "columnname": "crm_startdate", "filterSign": ">=", "widgettype": "combo", "dvquerytext": "Select start_date::date as id, start_date::date as idval FROM ext_cat_period WHERE id IS NOT NULL ORDER BY start_date desc", "isNullValue": "false", "layoutorder": 2, "showOnTableModel": {"status": true, "position": 2}}, {"label": "До дати", "datatype": "text", "columnname": "crm_enddate", "filterSign": "<=", "widgettype": "combo", "dvquerytext": "Select end_date::date as id, end_date::date as idval FROM ext_cat_period WHERE id IS NOT NULL ORDER BY end_date desc", "isNullValue": "false", "layoutorder": 3, "showOnTableModel": {"status": true, "position": 3}}]'),
    (104, '[{"label": "Експлуатація:", "datatype": "text", "columnname": "exploitation", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER by name", "isNullValue": "true", "layoutorder": 1}, {"label": "Dma:", "datatype": "text", "columnname": "dma", "widgettype": "combo", "dvquerytext": "Select name as id, name as idval FROM dma WHERE dma_id != -1 and dma_id!=0 ORDER BY name", "isNullValue": "true", "layoutorder": 2}, {"label": "Дата Початку", "datatype": "text", "columnname": "crm_startdate", "filterSign": ">=", "widgettype": "combo", "dvquerytext": "Select start_date::date as id, start_date::date as idval FROM ext_cat_period WHERE id IS NOT NULL ORDER BY start_date", "isNullValue": "false", "layoutorder": 3, "showOnTableModel": {"status": true, "position": 3}}, {"label": "Дата Завершення", "datatype": "text", "columnname": "crm_enddate", "filterSign": "<=", "widgettype": "combo", "dvquerytext": "Select end_date::date as id, end_date::date as idval FROM ext_cat_period WHERE id IS NOT NULL ORDER BY end_date desc", "isNullValue": "false", "layoutorder": 4, "showOnTableModel": {"status": true, "position": 4}}]')
) AS v(id, text)
