ue, "iseditable": true, "layoutname": "grl_option_parameters", "selectedId": "$userNodetype", "widgetname": "nodeType", "widgettype": "combo", "dvQueryText": "select distinct cfn.id as id, cfn.id as idval from cat_feature_node cfn JOIN cat_node cn ON cn.node_type=cfn.id where cfn.id is not null", "layoutorder": 7}, {"label": "Вузол каталог:", "value": null, "datatype": "text", "dvparentid": "node_type", "layoutname": "grl_option_parameters", "parentname": "nodeType", "selectedId": "$userNodecat", "widgetname": "nodeCat", "widgettype": "combo", "dvQueryText": "select distinct id as id, id as idval from cat_node order by id", "filterquery": "select distinct id as id, id as idval from cat_node where node_type = ''{parent_value}'' order by id", "layoutorder": 8, "dvquerytext_filterc": " AND value_state_type.state"}]'),
