    (2768, '[{"label": "Клас графа:", "tooltip": "Використаний метод Graphanalytics", "comboIds": ["PRESSZONE", "DQA", "DMA", "SECTOR"], "datatype": "text", "comboNames": ["Зонування тиску (PRESSZONE)", "Зони якості району (DQA)", "Зони вимірювання району (DMA)", "Секторизація входу (SECTOR-ALTO / SECTOR- BAJO)"], "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "graphClass", "widgettype": "combo", "layoutorder": 1}, {"label": "Експлуатація:", "tooltip": "Виберіть експлуатацію для роботи", "datatype": "text", "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "exploitation", "widgettype": "combo", "dvQueryText": "SELECT id, idval FROM ( SELECT -901 AS id, ''User selected expl'' AS idval, ''a'' AS sort_order UNION SELECT -902 AS id, ''All exploitations'' AS idval, ''b'' AS sort_order UNION SELECT expl_id AS id, name AS idval, ''c'' AS sort_order FROM exploitation WHERE active IS NOT FALSE ) a ORDER BY sort_order ASC, idval ASC", "layoutorder": 2}, {"label": "Примусово відкрити вузли: (*)", "value": null, "tooltip": "Опційні ідентифікатори вузлів для тимчасового відкриття закритих вузлів, щоб змусити алгоритм продовжити роботу там", "datatype": "text", "layoutname": "grl_option_parameters", "widgetname": "forceOpen", "widgettype": "linetext", "isMandatory": false, "layoutorder": 5, "placeholder": "1015,2231,3123"}, {"label": "Примусово закрити вузли: (*)", "value": null, "tooltip": "Опційні ідентифікатори вузлів для тимчасового закриття відкритих вузлів, щоб змусити алгоритм зупинитися там", "datatype": "text", "layoutname": "grl_option_parameters", "widgetname": "forceClosed", "widgettype": "text", "isMandatory": false, "layoutorder": 6, "placeholder": "1015,2231,3123"}, {"label": "Використовувати вибрані psectors:", "value": null, "tooltip": "Якщо true, використовувати вибрані psectors. Якщо false, ігнорувати вибрані psectors і працювати лише з мережею в експлуатації", "datatype": "boolean", "layoutname": "grl_option_parameters", "widgetname": "usePlanPsector", "widgettype": "check", "layoutorder": 7}, {"label": "Застосувати Зміни:", "value": null, "tooltip": "Якщо істина, зміни будуть застосовані до DB. Якщо хибно, результати алгоритму будуть збережені в anl таблицях", "datatype": "boolean", "layoutname": "grl_option_parameters", "widgetname": "commitChanges", "widgettype": "check", "layoutorder": 8}, {"label": "Метод побудови картозони:", "comboIds": [0, 1, 2, 3, 4], "datatype": "integer", "comboNames": ["ЖОДЕН", "ВГНУТИЙ ПОЛІГОН", "ТРУБНИЙ БУФЕР", "БУФЕР ДІЛЯНКИ ТА ТРУБОПРОВОДУ", "БУФЕР ЗВ''ЯЗКУ ТА ТРУБОПРОВОДУ"], "layoutname": "grl_option_parameters", "selectedId": null, "widgetname": "updateMapZone", "widgettype": "combo", "layoutorder": 10}, {"label": "Буфер Труби", "value": null, "tooltip": "Буфер від дуг для створення геометрії картозони, використовуючи опції [PIPE BUFFER]. Звичайні значення можуть бути в межах 3-20 mts.", "datatype": "float", "layoutname": "grl_option_parameters", "widgetname": "geomParamUpdate", "widgettype": "text", "isMandatory": false, "layoutorder": 11, "placeholder": "5-30"}, {"label": "Зони Карти З Нуля:", "value": null, "tooltip": "Якщо істина, зони карти обчислюються автоматично з нуля.", "datatype": "boolean", "layoutname": "grl_option_parameters", "widgetname": "fromZero", "widgettype": "check", "layoutorder": 12}]'),
